// POST api call
export async function POST(relativeUrl, data) {
  let url = Base_URL + relativeUrl;
  // console.log("\n\n url:: ", url, "\n data=>", data);
  try {
    const requestOptions = {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        "Access-Control-Allow-Origin": "*",
        "Access-Control-Allow-Methods": "GET,PUT,POST,DELETE,PATCH,OPTIONS",
        Authorization: `Bearer ${await getData(ACCESS_TOKEN)}`,
      },
      body: JSON.stringify(data),
    };
    const re = await fetch(url, requestOptions)
      .then((res) => res.json())
      .then(
        (result) => {
          return result;
        },
        (error) => {
          return error;
        }
      );

    return re;
  } catch (error) {
    if (error.response) {
      return error.response;
    } else if (error.request) {
      return error;
    } else {
      return error;
    }
  }
}
// GET api call
export async function GET(relativeUrl, data) {
  let url = Base_URL + relativeUrl;
  try {
    const requestOptions = {
      method: "GET",
      headers: { "Content-Type": "application/json" },
      Authorization: `Bearer ${await getData(ACCESS_TOKEN)}`,
      data: JSON.stringify(data),
    };
    const re = await fetch(url, requestOptions)
      .then((res) => res.json())
      .then(
        (result) => {
          return result;
        },
        (error) => {
          return error;
        }
      );
    return re;
  } catch (error) {
    if (error.response) {
      return error.response;
    } else if (error.request) {
      return error;
    } else {
      return error;
    }
  }
}
